const STORAGE_KEY="typeMasterStats";class Statistics{constructor(){this.data=this.load()}load(){try{const t=localStorage.getItem(STORAGE_KEY);if(t)return JSON.parse(t)}catch(t){console.error("Failed to load statistics:",t)}return{sessions:[],totalTime:0,completedLessons:0,bestSpeed:0,averageAccuracy:0,totalSessions:0,totalCharsTyped:0}}save(){try{localStorage.setItem(STORAGE_KEY,JSON.stringify(this.data))}catch(t){console.error("Failed to save statistics:",t)}}addSession(t){const s={timestamp:Date.now(),speed:t.speed||0,accuracy:t.accuracy||0,time:t.time||0,errors:t.errors||0,mode:t.mode||"unknown",layout:t.layout||"ru",lessonKey:t.lessonKey||null};this.data.sessions.push(s),this.data.totalSessions++,this.data.totalTime+=s.time;const e=Math.round((s.speed||0)*(s.time||0)/60);this.data.totalCharsTyped=(this.data.totalCharsTyped||0)+e,"lesson"===s.mode&&(this.data.completedLessons++,s.lessonKey&&this.updateLessonStats(s.lessonKey,s)),s.speed>this.data.bestSpeed&&(this.data.bestSpeed=s.speed);const a=this.data.sessions.reduce((t,s)=>t+s.accuracy,0);this.data.averageAccuracy=Math.round(a/this.data.sessions.length),this.save(),this.updateDisplay()}updateLessonStats(t,s){this.data.lessonStats||(this.data.lessonStats={}),(!this.data.lessonStats[t]||s.accuracy>this.data.lessonStats[t].accuracy)&&(this.data.lessonStats[t]={completed:!0,accuracy:s.accuracy,speed:s.speed,bestTime:s.time,timestamp:s.timestamp})}getLessonStats(t){return this.data.lessonStats&&this.data.lessonStats[t]||null}getTotalLessonsCount(){return"undefined"==typeof LESSONS_DATA?0:["beginner","medium","advanced"].reduce((t,s)=>t+(LESSONS_DATA[s]&&LESSONS_DATA[s].lessons?LESSONS_DATA[s].lessons.length:0),0)}updateDisplay(){const t=document.getElementById("bestSpeed"),s=document.getElementById("avgAccuracy"),e=document.getElementById("completedLessons"),a=document.getElementById("totalLessonsCount"),o=document.getElementById("totalTime"),n=document.getElementById("totalSessions"),d=document.getElementById("progressLessonsBar");t&&t.textContent!==String(this.data.bestSpeed)&&(t.textContent=this.data.bestSpeed);const i=this.data.averageAccuracy+"%";s&&s.textContent!==i&&(s.textContent=i);const l=this.data.lessonStats?Object.keys(this.data.lessonStats).length:0;e&&e.textContent!==String(l)&&(e.textContent=l);const c=this.getTotalLessonsCount();if(a&&a.textContent!==String(c)&&(a.textContent=c),d){const t=c>0?Math.min(100,Math.round(l/c*100)):0;d.style.width=t+"%"}if(o){const t=Math.floor(this.data.totalTime/60),s=Math.floor(t/60),e=s>0?s+"ч":t+"м";o.textContent!==e&&(o.textContent=e)}n&&n.textContent!==String(this.data.totalSessions)&&(n.textContent=this.data.totalSessions)}getRecentSessions(t=10){return this.data.sessions.slice(-t).reverse()}getBestSession(){return 0===this.data.sessions.length?null:this.data.sessions.reduce((t,s)=>!t||s.speed>t.speed?s:t,null)}getUniqueLessonsCount(){return this.data.lessonStats?Object.keys(this.data.lessonStats).length:0}getTotalWords(){return Math.floor((this.data.totalCharsTyped||0)/5)}reset(){confirm("Вы уверены, что хотите сбросить всю статистику?")&&(this.data={sessions:[],totalTime:0,completedLessons:0,bestSpeed:0,averageAccuracy:0,totalSessions:0,totalCharsTyped:0},this.save(),this.updateDisplay())}}const stats=new Statistics;window.statsModule=stats;